  'Street, town, postcode — where buyers collect': { en: 'Street, town, postcode — where buyers collect', es: 'Calle, población, código postal — donde recogen los compradores', de: 'Straße, Ort, PLZ — wo Käufer abholen', da: 'Gade, by, postnummer — hvor købere henter', sv: 'Gata, ort, postnummer — där köpare hämtar', nl: 'Straat, plaats, postcode — waar kopers ophalen', fr: 'Rue, ville, code postal — où les acheteurs récupèrent', pt: 'Rua, cidade, código postal — onde os compradores recolhem' },
